   801 | std::optional<bool>
   802 | ConstraintTy::isImpliedBy(const ConstraintSystem &CS) const {
   803 |   bool IsConditionImplied = CS.isConditionImplied(Coefficients);
   804 | 
   805 |   if (IsEq || IsNe) {
   806 |     auto NegatedOrEqual = ConstraintSystem::negateOrEqual(Coefficients);
   807 |     bool IsNegatedOrEqualImplied =
   808 |         !NegatedOrEqual.empty() && CS.isConditionImplied(NegatedOrEqual);
   809 | 
   810 |     // In order to check that `%a == %b` is true (equality), both conditions `%a
   811 |     // >= %b` and `%a <= %b` must hold true. When checking for equality (`IsEq`
   812 |     // is true), we return true if they both hold, false in the other cases.
   813 |     if (IsConditionImplied && IsNegatedOrEqualImplied)
   814 |       return IsEq;
   815 | 
   816 |     auto Negated = ConstraintSystem::negate(Coefficients);
   817 |     bool IsNegatedImplied = !Negated.empty() && CS.isConditionImplied(Negated);
   818 | 
   819 |     auto StrictLessThan = ConstraintSystem::toStrictLessThan(Coefficients);
   820 |     bool IsStrictLessThanImplied =
   821 |         !StrictLessThan.empty() && CS.isConditionImplied(StrictLessThan);
   822 | 
   823 |     // In order to check that `%a != %b` is true (non-equality), either
   824 |     // condition `%a > %b` or `%a < %b` must hold true. When checking for
   825 |     // non-equality (`IsNe` is true), we return true if one of the two holds,
   826 |     // false in the other cases.
   827 |     if (IsNegatedImplied || IsStrictLessThanImplied)
   828 |       return IsNe;
   829 | 
   830 |     return std::nullopt;
   831 |   }
   832 | 
   833 |   if (IsConditionImplied)
   834 |     return true;
   835 | 
   836 |   auto Negated = ConstraintSystem::negate(Coefficients);
   837 |   auto IsNegatedImplied = !Negated.empty() && CS.isConditionImplied(Negated);
   838 |   if (IsNegatedImplied)
   839 |     return false;
   840 | 
   841 |   // Neither the condition nor its negated holds, did not prove anything.
   842 |   return std::nullopt;
   843 | }
